<template>\n  <div class="calendar">\n    <div class="calendar-header">\n      <button @click="prevMonth">&lt;</button>\n      <span>{{ currentMonth }} {{ currentYear }}</span>\n      <button @click="nextMonth">&gt;</button>\n    </div>\n    <div class="calendar-grid">\n      <div class="calendar-day" v-for="day in daysInMonth" :key="day">\n        <div class="day-number">{{ day }}</div>\n        <div class="events">\n          <div v-for="event in getEventsForDay(day)" :key="event.id" class="event">\n            <span>{{ event.name }}</span>\n            <button @click="$emit('register', event.id)">Register</button>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n</template>\n\n<script>\nexport default {\n  data() {\n    return {\n      currentMonth: new Date().toLocaleString('default', { month: 'long' }),\n      currentYear: new Date().getFullYear(),\n    };\n  },\n  props: {\n    events: {\n      type: Array,\n      required: true,\n    },\n  },\n  computed: {\n    daysInMonth() {\n      const date = new Date(this.currentYear, new Date().getMonth() + 1, 0);\n      return Array.from({ length: date.getDate() }, (_, i) => i + 1);\n    },\n  },\n  methods: {\n    getEventsForDay(day) {\n      return this.events.filter(event => new Date(event.date).getDate() === day);\n    },\n    prevMonth() {\n      // Logic to go to the previous month\n    },\n    nextMonth() {\n      // Logic to go to the next month\n    },\n  },\n};\n</script>\n\n<style scoped>\n.calendar {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n}\n.calendar-header {\n  display: flex;\n  justify-content: space-between;\n  width: 100%;\n  padding: 10px;\n  background-color: #f0f0f0;\n}\n.calendar-grid {\n  display: grid;\n  grid-template-columns: repeat(7, 1fr);\n  gap: 5px;\n}\n.calendar-day {\n  border: 1px solid #ddd;\n  padding: 5px;\n  min-height: 100px;\n}\n.day-number {\n  font-weight: bold;\n}\n.event {\n  background-color: #e0e0e0;\n  margin: 2px 0;\n  padding: 2px;\n  border-radius: 3px;\n}\n</style> 